var raw = $input.first().json;
var body = raw.body || raw;
var data = body.data || body;
var tenantId = String(body.tenantId || data.tenantId || '');
var id = String(data.id || '');

function esc(v) {
  return v == null ? '' : String(v).replace(/'/g, "''");
}

const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(tenantId)) throw new Error('Invalid tenantId');
if (!uuidRegex.test(id)) throw new Error('Invalid id');

var now = new Date().toISOString();

// Si on fournit salaireBase (ou primes/heuresSupp), on recalcule tout
var recalcul = data.salaireBase !== undefined || data.primes !== undefined || data.heuresSupp25 !== undefined || data.heuresSupp50 !== undefined;

if (recalcul) {
  var salaireBase = Number(data.salaireBase || 0);
  var primes = Number(data.primes || 0);
  var heuresSupp25 = Number(data.heuresSupp25 || 0);
  var heuresSupp50 = Number(data.heuresSupp50 || 0);
  var isCadre = data.isCadre !== undefined ? Boolean(data.isCadre) : true;
  var tauxImposition = Number(data.tauxImposition || 0);

  // Calcul heures supp
  var tauxHoraire = salaireBase / 151.67;
  var montantHS25 = heuresSupp25 * tauxHoraire * 1.25;
  var montantHS50 = heuresSupp50 * tauxHoraire * 1.50;
  var totalHS = montantHS25 + montantHS50;

  var brut = salaireBase + primes + totalHS;
  var PMSS = 3925;
  var tranche1 = Math.min(brut, PMSS);
  var tranche2 = Math.max(0, brut - PMSS);

  // Cotisations salariales
  var sal = {};
  sal.vieillessePlafonnee = tranche1 * 0.069;
  sal.vieillesseDeplafonnee = brut * 0.004;
  sal.agircArrcoT1 = tranche1 * 0.0315;
  sal.agircArrcoT2 = tranche2 * 0.0864;
  sal.csgDeductible = brut * 0.9825 * 0.068;
  sal.csgNonDeductible = brut * 0.9825 * 0.024;
  sal.crds = brut * 0.9825 * 0.005;
  sal.apecCadre = isCadre ? brut * 0.00024 : 0;
  var totalSalariales = Object.values(sal).reduce((a, b) => a + b, 0);

  // Cotisations patronales
  var pat = {};
  pat.assuranceMaladie = brut <= PMSS * 2.5 ? brut * 0.07 : brut * 0.13;
  pat.vieillessePlafonnee = tranche1 * 0.0855;
  pat.vieillesseDeplafonnee = brut * 0.0202;
  pat.allocFamiliales = brut <= PMSS * 3.5 ? brut * 0.0345 : brut * 0.0525;
  pat.agircArrcoT1 = tranche1 * 0.0472;
  pat.agircArrcoT2 = tranche2 * 0.1295;
  pat.chomage = brut * 0.0405;
  pat.ags = brut * 0.002;
  pat.fnal = brut * 0.001;
  pat.formationPro = brut * 0.0055;
  pat.taxeApprentissage = brut * 0.0068;
  pat.csa = brut * 0.003;
  pat.atMp = brut * 0.0128;
  pat.apecCadre = isCadre ? brut * 0.00036 : 0;
  pat.prevoyanceCadre = isCadre ? tranche1 * 0.015 : 0;
  var totalPatronales = Object.values(pat).reduce((a, b) => a + b, 0);

  var netImposable = brut - totalSalariales + sal.csgNonDeductible + sal.crds;
  var pas = netImposable * (tauxImposition / 100);
  var netAPayer = brut - totalSalariales - pas;
  var deductions = totalSalariales + pas;

  var detail = {
    brut: Math.round(brut * 100) / 100,
    heuresSupp: { h25: heuresSupp25, h50: heuresSupp50, montant: Math.round(totalHS * 100) / 100 },
    isCadre: isCadre,
    cotisationsSalariales: {},
    cotisationsPatronales: {},
    totalSalariales: Math.round(totalSalariales * 100) / 100,
    totalPatronales: Math.round(totalPatronales * 100) / 100,
    netImposable: Math.round(netImposable * 100) / 100,
    pas: { taux: tauxImposition, montant: Math.round(pas * 100) / 100 },
    netAPayer: Math.round(netAPayer * 100) / 100,
    coutTotal: Math.round((brut + totalPatronales) * 100) / 100
  };
  for (var k in sal) detail.cotisationsSalariales[k] = Math.round(sal[k] * 100) / 100;
  for (var k in pat) detail.cotisationsPatronales[k] = Math.round(pat[k] * 100) / 100;

  var commentaireJson = JSON.stringify(detail);

  var query = "UPDATE rh_bulletins_paie SET " +
    "salaire_base = " + Math.round(salaireBase * 100) / 100 + ", " +
    "primes = " + Math.round(primes * 100) / 100 + ", " +
    "deductions = " + Math.round(deductions * 100) / 100 + ", " +
    "charges_patronales = " + Math.round(totalPatronales * 100) / 100 + ", " +
    "charges_salariales = " + Math.round(totalSalariales * 100) / 100 + ", " +
    "net_a_payer = " + Math.round(netAPayer * 100) / 100 + ", " +
    "net_imposable = " + Math.round(netImposable * 100) / 100 + ", " +
    "commentaire = '" + esc(commentaireJson) + "', " +
    (data.statut ? "statut = '" + esc(data.statut) + "', " : "") +
    "updated_at = '" + esc(now) + "' " +
    "WHERE tenant_id = '" + esc(tenantId) + "' AND id = '" + esc(id) + "' RETURNING *;";

  return [{json: {query: query}}];
} else {
  // Mise à jour simple (statut, commentaire, etc.)
  var setParts = ["updated_at = '" + esc(now) + "'"];
  if (data.statut !== undefined) setParts.push("statut = '" + esc(data.statut) + "'");
  if (data.commentaire !== undefined) setParts.push("commentaire = '" + esc(data.commentaire) + "'");

  var query = "UPDATE rh_bulletins_paie SET " + setParts.join(', ') +
    " WHERE tenant_id = '" + esc(tenantId) + "' AND id = '" + esc(id) + "' RETURNING *;";

  return [{json: {query: query}}];
}

const row = $input.first().json;
if (!row || !row.id) {
  return [{json: {success: false, error: 'Bulletin non trouvé'}}];
}

// Parse les cotisations détaillées depuis le commentaire si disponible
var detailCotisations = null;
if (row.commentaire) {
  try {
    var parsed = JSON.parse(row.commentaire);
    if (parsed.cotisations || parsed.detail) {
      detailCotisations = parsed;
    }
  } catch(e) {
    // commentaire est du texte libre, pas du JSON
  }
}

var result = {
  id: row.id,
  memberId: row.member_id,
  membreNom: ((row.membre_nom || '') + ' ' + (row.membre_prenom || '')).trim(),
  membrePoste: row.membre_poste || null,
  membreDepartement: row.membre_departement || null,
  mois: Number(row.mois || 0),
  annee: Number(row.annee || 0),
  periode: String(row.mois || 0).padStart(2, '0') + '/' + (row.annee || ''),
  salaireBase: Number(row.salaire_base || 0),
  primes: Number(row.primes || 0),
  salaireBrut: Number(row.salaire_base || 0) + Number(row.primes || 0),
  deductions: Number(row.deductions || 0),
  chargesPatronales: Number(row.charges_patronales || 0),
  chargesSalariales: Number(row.charges_salariales || 0),
  netAPayer: Number(row.net_a_payer || 0),
  netImposable: Number(row.net_imposable || 0),
  coutTotal: Number(row.salaire_base || 0) + Number(row.primes || 0) + Number(row.charges_patronales || 0),
  statut: row.statut || 'brouillon',
  commentaire: detailCotisations ? null : (row.commentaire || null),
  detailCotisations: detailCotisations,
  createdAt: row.created_at,
  updatedAt: row.updated_at
};

return [{json: {success: true, data: result}}];
